@app.post("/screenshot")
def screenshot():
    if not S3_BUCKET:
        return jsonify({"error": "S3_BUCKET is not configured"}), 500

    payload = request.get_json(silent=True) or {}
    raw_url = payload.get("url") or request.args.get("url")

    try:
        url = normalize_url(raw_url)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    key = build_s3_key(url)
    image_url = None
    cached = False

    try:
        if object_exists(S3_BUCKET, key):
            image_url = upload_url_for_existing(key)
            cached = True
        else:
            screenshot_png = capture_screenshot_bytes(url)
            thumbnail_bytes = make_thumbnail(screenshot_png)
            image_url = upload_to_s3(
                thumbnail_bytes,
                key,
                content_type_for_format(SCREENSHOT_FORMAT),
                url,
            )
    except Exception as e:
        logger.exception("Failed to generate screenshot")
        return jsonify({"error": str(e)}), 500

    return jsonify(
        {
            "url": url,
            "s3_bucket": S3_BUCKET,
            "s3_key": key,
            "image_url": image_url,
            "cached": cached,
            "thumbnail_width": THUMBNAIL_WIDTH,
            "thumbnail_height": THUMBNAIL_HEIGHT,
            "format": SCREENSHOT_FORMAT,
        }
    )


def upload_url_for_existing(key: str) -> str:
    if S3_PUBLIC_BASE_URL:
        return f"{S3_PUBLIC_BASE_URL.rstrip('/')}/{key}"
    return f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{key}"


@app.get("/preview")
def preview():
    if not ENABLE_LOCAL_PREVIEW:
        return jsonify({"error": "Local preview disabled"}), 403

    raw_url = request.args.get("url")
    try:
        url = normalize_url(raw_url)
        screenshot_png = capture_screenshot_bytes(url)
        thumbnail_bytes = make_thumbnail(screenshot_png)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        logger.exception("Preview generation failed")
        return jsonify({"error": str(e)}), 500

    mime = content_type_for_format(SCREENSHOT_FORMAT)
    ext = "jpg" if SCREENSHOT_FORMAT in ("jpg", "jpeg") else "png"
    return send_file(
        io.BytesIO(thumbnail_bytes),
        mimetype=mime,
        download_name=f"preview.{ext}",
    )


